// Close Webhook Payload extrahieren und Subworkflow-ID bestimmen
const body = $json.body || $json;
const event = body.event || body;
const data = event.data || event;

// Draft-Schutz: Nur published Activities verarbeiten.
// Close feuert 'created' auch bei Drafts — ignorieren wenn nicht published.
// Beim Publishen feuert Close ein 'updated' Event mit last_published_at gesetzt.
const action = event.action || '';
const previousData = event.previous_data || {};

// Nicht published? → Ignorieren (Draft)
if (!data.last_published_at) {
  return [];
}

// Duplicate-Schutz: War schon vorher published → re-publish/Feld-Update ignorieren
if (action === 'updated' && previousData.last_published_at != null) {
  return [];
}

const activityId = data.id;
const leadId = data.lead_id;
const userId = data.user_id || data.created_by || null;
const typeId = data.custom_activity_type_id;
const dateCreated = data.date_created || new Date().toISOString();

// Custom Fields extrahieren (custom.cf_xxx)
const customFields = {};
for (const [key, value] of Object.entries(data)) {
  if (key.startsWith('custom.')) {
    customFields[key] = value;
  }
}

// Activity Type → Workflow ID Mapping
const TYPE_MAP = {
  'actitype_6GTMexlVYwCl3ER9rYB4x4': { route: 'eg-vereinbart-et', workflowId: 'ricQtoIQTyDVTzg4' },
  'actitype_4jcmhCre676aqKjDVWqODu': { route: 'eg-vereinbart-ft', workflowId: 'ricQtoIQTyDVTzg4' },
  'actitype_5lGDZdgbNYgL7ii0Bbjno9': { route: 'eg-noshow', workflowId: 'c78XK8bSSiqPr3ql' },
  'actitype_0Pow7dFbqAOrFjLsCT068D': { route: 'eg-stattgefunden', workflowId: 'Vk7mEgStattgef23' },
  'actitype_1t4dAEI4JjnbDr6mRnECr0': { route: 'sg-stattgefunden', workflowId: 'iFvQIe00lE8nlbLR' },
  'actitype_0kl5mkpGgPgDhbQEYKyJvD': { route: 'sg-noshow', workflowId: 'fSmzaHFL7D09qwQA' },
  'actitype_4SrDqCdE7yZuxZrw3YxoLI': { route: 'angebot-erstellen', workflowId: 'WsskE1gcLnou2UFQ' },
  'actitype_3dEZCczRxJQieHfSCDW3bg': { route: 'kunde-gewonnen', workflowId: '9GG7yBEefplT3uwu' },
  'actitype_6dqeewSGR6SAXD6ZH9xbM3': { route: 'kunde-verloren', workflowId: 'mhLb61HZiNAj11SB' }
};

const mapping = TYPE_MAP[typeId];
if (!mapping) {
  return [];
}

return [{
  json: {
    activityId,
    leadId,
    userId,
    typeId,
    dateCreated,
    customFields,
    _route: mapping.route,
    _workflowId: mapping.workflowId,
    rawEvent: event
  }
}];
